import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axiosInstance from '../../api/axiosInstance';

const VerifyEmail = () => {
    const { token } = useParams();
    const navigate = useNavigate();
    const [status, setStatus] = useState('verifying'); // verifying, success, error
    const [message, setMessage] = useState('Verifying your email...');

    useEffect(() => {
        const verify = async () => {
            try {
                // Using axiosInstance directly as this method might not be in authAPI yet
                // Or I should add it to authAPI. 
                // Let's use direct axios for now to ensure path.
                const response = await axiosInstance.get(`/auth/verify-email/${token}/`);
                setStatus('success');
                setMessage(response.data.message || 'Email verified successfully!');

                // Redirect after few seconds
                setTimeout(() => {
                    navigate('/login');
                }, 3000);
            } catch (error) {
                setStatus('error');
                setMessage(error.response?.data?.message || 'Verification failed. Link may be invalid or expired.');
            }
        };

        if (token) {
            verify();
        } else {
            setStatus('error');
            setMessage('Invalid verification link.');
        }
    }, [token, navigate]);

    return (
        <div className="d-flex align-items-center justify-content-center vh-100 bg-light">
            <div className="card shadow p-5 text-center" style={{ maxWidth: '500px' }}>
                <div className="mb-4">
                    {status === 'verifying' && <div className="spinner-border text-primary" role="status"></div>}
                    {status === 'success' && <i className="bi bi-check-circle-fill text-success display-1"></i>}
                    {status === 'error' && <i className="bi bi-x-circle-fill text-danger display-1"></i>}
                </div>

                <h3 className="mb-3">
                    {status === 'verifying' && 'Verifying Email'}
                    {status === 'success' && 'Email Verified!'}
                    {status === 'error' && 'Verification Failed'}
                </h3>

                <p className="text-muted mb-4">{message}</p>

                {status === 'success' && <p>Redirecting to login...</p>}

                {status === 'error' && (
                    <button className="btn btn-primary" onClick={() => navigate('/login')}>
                        Go to Login
                    </button>
                )}
            </div>
        </div>
    );
};

export default VerifyEmail;
